mapper.select:
SELECT * FROM data_authorization
WHERE grantor_id = #{grantorId}
  AND grantee_id = #{granteeId}
ORDER BY id DESC
    LIMIT 1

SELECT * FROM data_authorization
WHERE grantee_id = #{userId}
  AND (expire_time IS NULL OR expire_time > NOW())

SELECT * FROM data_authorization
WHERE family_id = #{familyId}
  AND (expire_time IS NULL OR expire_time > NOW())

mapper.update:
UPDATE data_authorization
SET data_types = #{dataTypes, typeHandler=com.baomidou.mybatisplus.extension.handlers.JacksonTypeHandler},
    expire_time = #{expireTime},
    updated_at = #{updatedAt}
WHERE id = #{id}
